package sshkey

import "testing"

// Keys generated by ssh-keygen; the fingerprints / types / comments are exactly
// what `ssh-keygen -l` reports for each.
const (
	edB64 = ""
	edFP  = "SHA256:MZKQua1F1vZJsJHw0RgG/BgnUpAbZZOkJdElEc0lDR4"

	edEncB64 = ""
	edEncFP  = "SHA256:reHjqbMmpXE9UTPUpQFzJCNWa7eCAIvLfJqy6OBH4cI"

	rsaB64 = ""
	rsaFP  = "SHA256:ZQknCC+6oSY+g/uMq6ymqdjcR1g2+TmOrZzCaCSNtD0"
)

func TestUnencryptedEd25519(t *testing.T) {
	r, err := Decode(edB64)
	if err != nil {
		t.Fatalf("Decode: %v", err)
	}
	if r.Encrypted || r.Cipher != "none" {
		t.Errorf("should be unencrypted: cipher=%q enc=%v", r.Cipher, r.Encrypted)
	}
	if len(r.Keys) != 1 || r.Keys[0].Type != "ssh-ed25519" {
		t.Fatalf("keys: %+v", r.Keys)
	}
	if r.Keys[0].Fingerprint != edFP {
		t.Errorf("fingerprint = %q, want %q", r.Keys[0].Fingerprint, edFP)
	}
	if r.Comment != "alice@victim" {
		t.Errorf("comment = %q, want alice@victim", r.Comment)
	}
}

func TestEncryptedEd25519(t *testing.T) {
	r, err := Decode(edEncB64)
	if err != nil {
		t.Fatalf("Decode: %v", err)
	}
	if !r.Encrypted || r.Cipher != "aes256-ctr" {
		t.Errorf("should be encrypted aes256-ctr: cipher=%q enc=%v", r.Cipher, r.Encrypted)
	}
	if r.KDF != "bcrypt" || r.KDFRounds != 24 || r.KDFSaltLen != 16 {
		t.Errorf("kdf = %q rounds=%d saltlen=%d, want bcrypt/24/16", r.KDF, r.KDFRounds, r.KDFSaltLen)
	}
	if r.Keys[0].Fingerprint != edEncFP {
		t.Errorf("fingerprint = %q, want %q", r.Keys[0].Fingerprint, edEncFP)
	}
	// The comment is in the encrypted section — must NOT be guessed.
	if r.Comment != "" {
		t.Errorf("encrypted key comment should be empty, got %q", r.Comment)
	}
	if r.Note == "" {
		t.Error("encrypted key should carry a crack-guidance note")
	}
}

func TestUnencryptedRSA(t *testing.T) {
	r, err := Decode(rsaB64)
	if err != nil {
		t.Fatalf("Decode: %v", err)
	}
	if r.Keys[0].Type != "ssh-rsa" || r.Keys[0].Fingerprint != rsaFP {
		t.Errorf("rsa key: type=%q fp=%q", r.Keys[0].Type, r.Keys[0].Fingerprint)
	}
	if r.Comment != "svc@host" {
		t.Errorf("comment = %q, want svc@host", r.Comment)
	}
}

// TestPEMArmorTolerated confirms the full PEM (with header/footer) decodes too.
func TestPEMArmorTolerated(t *testing.T) {
	pem := "-----BEGIN OPENSSH PRIVATE KEY-----\n" + edB64 + "\n-----END OPENSSH PRIVATE KEY-----\n"
	r, err := Decode(pem)
	if err != nil {
		t.Fatalf("Decode(PEM): %v", err)
	}
	if r.Keys[0].Fingerprint != edFP {
		t.Errorf("PEM decode fingerprint = %q", r.Keys[0].Fingerprint)
	}
}

func TestRejectsMalformed(t *testing.T) {
	for _, c := range []string{
		"",
		"not base64 @@@",
		"aGVsbG8gd29ybGQ=", // valid base64 but wrong magic
	} {
		if _, err := Decode(c); err == nil {
			t.Errorf("Decode(%q): want error, got nil", c)
		}
	}
}
